///
/// No frames are mapped here — pages fault in lazily on first touch and are
/// resolved through [`contains`] in the fault path.
pub fn mmap(nr: i32, len: u64) -> Result<u64, i32> {
    client_mut(nr).ok_or(EINVAL)?.mmap(len)
}

