/// `nr` is untrackable or no `Mmap` region starts at `addr`.
pub fn munmap(nr: i32, addr: u64, len: u64) -> Result<(u64, u64), i32> {
    client_mut(nr).ok_or(EINVAL)?.munmap(addr, len)
}

